"use client"

import { motion } from "framer-motion"
import { Button } from "@/components/ui/button"
import { ArrowRight, CheckCircle2, Heart, TrendingUp, Scale, Activity, Wrench } from "lucide-react"
import type { NicheData } from "@/lib/niches"

interface NicheHeroProps {
  niche: NicheData
}

export function NicheHero({ niche }: NicheHeroProps) {
  // Map icon names to components
  const iconMap = {
    'Heart': Heart,
    'TrendingUp': TrendingUp,
    'Scale': Scale,
    'Activity': Activity,
    'Wrench': Wrench
  }

  const IconComponent = iconMap[niche.icon as keyof typeof iconMap] || Activity

  return (
    <section className={`relative min-h-screen flex items-center justify-center overflow-hidden ${niche.color.secondary}`}>
      {/* Animated background elements */}
      <div className="absolute inset-0">
        <div className={`absolute top-1/4 left-1/4 w-72 h-72 ${niche.color.gradient} rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-float`}></div>
        <div className={`absolute top-3/4 right-1/4 w-72 h-72 ${niche.color.gradient} rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-float`} style={{ animationDelay: '2s' }}></div>
        <div className={`absolute bottom-1/4 left-1/3 w-72 h-72 ${niche.color.gradient} rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-float`} style={{ animationDelay: '4s' }}></div>
      </div>

      <div className="container mx-auto px-6 lg:px-8 relative z-10">
        <div className="grid lg:grid-cols-2 gap-16 items-center">
          {/* Left Content */}
          <div>
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6 }}
              className="mb-8"
            >
              <div className="inline-flex items-center gap-4 mb-6">
                <div className={`w-16 h-16 ${niche.color.gradient} rounded-2xl flex items-center justify-center shadow-2xl`}>
                  <IconComponent className="w-8 h-8 text-white" />
                </div>
                <div>
                  <div className="text-sm font-medium text-gray-600 uppercase tracking-wide">{niche.industry}</div>
                  <div className="text-3xl font-bold text-gray-900">{niche.name}</div>
                </div>
              </div>

              <h1 className="text-5xl md:text-6xl lg:text-7xl font-bold text-gray-900 mb-6 text-balance">
                {niche.tagline}
              </h1>

              <p className="text-xl md:text-2xl text-gray-700 mb-8 leading-relaxed text-balance">
                {niche.description}
              </p>

              <div className="flex flex-col sm:flex-row gap-4 mb-12">
                <Button variant="gradient" size="xl" className="group">
                  {niche.cta.primary}
                  <ArrowRight className="w-5 h-5 ml-2 group-hover:translate-x-1 transition-transform" />
                </Button>
                <Button variant="outline" size="xl" className="border-gray-300 text-gray-700 hover:bg-gray-50">
                  {niche.cta.secondary}
                </Button>
              </div>

              {/* Target Audience */}
              <div className="space-y-3">
                <div className="text-sm font-medium text-gray-600 uppercase tracking-wide">Perfect for:</div>
                <div className="flex flex-wrap gap-2">
                  {niche.targetAudience.map((audience, index) => (
                    <div key={index} className="flex items-center gap-2 px-3 py-2 bg-white rounded-lg border border-gray-200">
                      <CheckCircle2 className="w-4 h-4 text-green-600" />
                      <span className="text-sm font-medium text-gray-700">{audience}</span>
                    </div>
                  ))}
                </div>
              </div>
            </motion.div>
          </div>

          {/* Right Metrics */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.3 }}
            className="space-y-8"
          >
            <div className="text-center mb-8">
              <h3 className="text-2xl font-bold text-gray-900 mb-2">Proven Results</h3>
              <p className="text-gray-600">From practices using FN3 Hive automation</p>
            </div>

            {niche.metrics.map((metric, index) => (
              <motion.div
                key={metric.label}
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ duration: 0.6, delay: 0.4 + index * 0.1 }}
                className="bg-white rounded-3xl p-8 shadow-lg border border-gray-200"
              >
                <div className="text-center">
                  <div className={`text-4xl font-bold bg-gradient-to-r ${niche.color.primary} bg-clip-text text-transparent mb-2`}>
                    {metric.value}
                  </div>
                  <div className="text-lg font-semibold text-gray-900 mb-2">{metric.label}</div>
                  <div className="text-gray-600 text-sm">{metric.description}</div>
                </div>
              </motion.div>
            ))}

            {niche.testimonial && (
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.6, delay: 0.8 }}
                className="bg-white rounded-3xl p-8 shadow-lg border border-gray-200"
              >
                <blockquote className="text-lg text-gray-700 italic mb-4">
                  "{niche.testimonial.quote}"
                </blockquote>
                <div className="flex items-center gap-3">
                  <div className={`w-12 h-12 ${niche.color.gradient} rounded-full flex items-center justify-center text-white font-bold text-lg`}>
                    {niche.testimonial.author.split(' ').map(n => n[0]).join('')}
                  </div>
                  <div>
                    <div className="font-semibold text-gray-900">{niche.testimonial.author}</div>
                    <div className="text-sm text-gray-600">{niche.testimonial.role}, {niche.testimonial.company}</div>
                  </div>
                </div>
              </motion.div>
            )}
          </motion.div>
        </div>
      </div>
    </section>
  )
}